const data = $input.first().json;
const products = data.products || [];
const configuredDomain = '__SHOPIFY_STORE_DOMAIN__';
const adminBase = '__SHOPIFY_ADMIN_API_BASE_URL__';
const storeCurrency = '__SHOPIFY_STORE_CURRENCY__';
const inferredDomain = adminBase.replace(/^https?:\/\//i, '').split('/')[0].toLowerCase();
const resolvedDomain = configuredDomain.includes('__SHOPIFY_STORE_DOMAIN__') ? inferredDomain : configuredDomain.toLowerCase().replace(/^https?:\/\//i, '').replace(/\/$/, '');
if (!resolvedDomain) {
  throw new Error('Could not resolve shop_domain. Set __SHOPIFY_STORE_DOMAIN__ or __SHOPIFY_ADMIN_API_BASE_URL__.');
}
return products.map((p) => ({
  json: {
    webhook_topic: 'products/create',
    event_id: `backfill-${p.id}-${new Date().toISOString()}`,
    envelope: {
      shop_domain: resolvedDomain,
      store_currency: storeCurrency.includes('__SHOPIFY_STORE_CURRENCY__') ? null : storeCurrency.toUpperCase(),
      event_id: `backfill-${p.id}-${new Date().toISOString()}`,
      occurred_at: p.updated_at || p.created_at || new Date().toISOString(),
      payload: p
    }
  }
}));
